const QUESTIONS_CISSP_C4 = [
  { id:30701, domain:8, level:2, question:"What is the primary goal of secure software design?", options:["A Building security into software from the start to reduce vulnerabilities","B Maximizing application performance while maintaining functionality","C Documenting all security requirements for compliance audits","D Implementing security controls as a final step before release"], correct:0, explanation:"Secure software design integrates security principles (least privilege, defense in depth, fail secure) from initial design, significantly reducing vulnerabilities compared to retrofitting security after development." },
  { id:30702, domain:8, level:2, question:"What is the primary purpose of a software assurance program?", options:["A Ensuring software is delivered on time and within budget","B Certifying software vendors meet organizational security standards","C Providing confidence that software is free from vulnerabilities and operates as intended","D Managing software licensing compliance across the enterprise"], correct:2, explanation:"Software assurance provides confidence that software is free from vulnerabilities and operates as intended, through processes like secure coding standards, code review, security testing, and formal verification methods." },
  { id:30703, domain:8, level:2, question:"What is the risk associated with using publicly known default credentials?", options:["A Default credentials may not meet password complexity requirements","B Attackers routinely try default credentials as a first step in attacking systems","C Default credentials cannot be changed without reinstalling the system","D Default credentials are stored in plaintext in configuration files"], correct:1, explanation:"Many systems ship with well-known default credentials (admin/admin, root/root). Attackers routinely attempt these credentials in automated attacks, so changing defaults before deployment is a critical first hardening step." },
  { id:30704, domain:8, level:2, question:"What is the concept of fail-safe defaults in secure coding?", options:["A Applications automatically recover from security failures without data loss","B Applications fall back to less secure but functional states during errors","C Default configurations should deny access unless explicitly granted","D Default settings prioritize safety over security in emergency situations"], correct:2, explanation:"Fail-safe defaults mean access is denied unless explicitly granted—the default state is the most restrictive. This prevents new features or configuration errors from unintentionally granting unauthorized access." },
  { id:30705, domain:8, level:2, question:"What does 'security debt' mean in software development?", options:["A The financial cost of remediating security vulnerabilities","B The difference between current and target security maturity levels","C Security obligations incurred through third-party dependencies","D The accumulation of security shortcuts and deferred security work that must eventually be addressed"], correct:3, explanation:"Security debt accumulates when development teams skip security reviews, defer vulnerability fixes, or take shortcuts. Like technical debt, it grows over time and becomes increasingly costly and risky to address later." },
  { id:30706, domain:8, level:2, question:"What is the primary purpose of application security testing in agile development?", options:["A Integrating continuous security testing throughout sprints for immediate developer feedback","B Conducting comprehensive security tests at the end of each sprint","C Delegating all security testing to a dedicated security team","D Testing only features with security-related requirements each sprint"], correct:0, explanation:"In agile, security testing is integrated throughout sprints—SAST on every commit, security stories in backlog, security acceptance criteria—providing immediate feedback so developers fix issues while the code is fresh." },
  { id:30707, domain:8, level:2, question:"What is the OWASP Application Security Verification Standard (ASVS)?", options:["A A framework for scoring web application vulnerabilities by severity","B A framework defining security requirements and verification criteria for web applications","C A list of approved security testing tools for web application testing","D A certification standard for web application security professionals"], correct:1, explanation:"OWASP ASVS provides three levels of security verification requirements for web applications—covering authentication, session management, cryptography, input validation—used to define security requirements and verify implementations." },
  { id:30708, domain:8, level:2, question:"What is the security concern with XML bomb (billion laughs) attacks?", options:["A XML parsers execute embedded JavaScript in XML data","B Deeply nested XML entities cause exponential memory consumption, crashing the parser","C XML documents containing SQL code execute against backend databases","D Malformed XML causes buffer overflows in the parsing engine"], correct:1, explanation:"XML bombs (billion laughs attacks) use nested entity references that expand exponentially, causing XML parsers to consume enormous amounts of memory/CPU when processing a small document, resulting in denial of service." },
  { id:30709, domain:8, level:2, question:"What is the purpose of security assertions in unit tests?", options:["A Verifying that the application meets compliance requirements","B Verifying that security tool licenses are valid","C Asserting that developers have completed security training","D Testing that security controls function correctly at the code level"], correct:3, explanation:"Security assertions in unit tests verify that security controls work correctly—that access control functions deny unauthorized requests, input validation rejects malicious input, and cryptographic functions produce correct outputs." },
  { id:30710, domain:8, level:2, question:"What is the concept of secure by design versus secure by deployment?", options:["A Secure by design is more expensive; secure by deployment is more practical","B Secure by design is a developer responsibility; secure by deployment is an operations responsibility","C Secure by design applies to software; secure by deployment applies to infrastructure","D Secure by design builds security into architecture; secure by deployment applies controls externally after development"], correct:3, explanation:"Secure by design builds security into architecture and code from the start. Secure by deployment relies on external controls (WAF, network rules) to compensate for insecure applications—less effective and more expensive than addressing root causes." },
  { id:30711, domain:7, level:2, question:"What is the primary purpose of security information management (SIM)?", options:["A Managing the lifecycle of security tools and technologies","B Monitoring the security posture of third-party vendors","C Collecting, normalizing, and long-term retention of security event data for compliance and analysis","D Managing security team information and communications"], correct:2, explanation:"SIM focuses on log management—collecting, normalizing, storing, and providing access to security event data for compliance reporting, long-term trend analysis, and historical investigation, as distinct from real-time correlation (SEM)." },
  { id:30712, domain:7, level:2, question:"What is the concept of 'assume breach' in security operations?", options:["A Assuming all security incidents will become data breaches","B Planning security controls assuming perimeter defenses will fail","C Assuming all employee devices are compromised","D Operating with the assumption that attackers are already in the environment"], correct:3, explanation:"'Assume breach' is a security posture that assumes attackers have or will gain entry, shifting focus to detection, containment, and resilience rather than solely preventing initial access, enabling more effective defense-in-depth strategies." },
  { id:30713, domain:7, level:2, question:"What is the purpose of a network flow analysis tool?", options:["A Capturing and inspecting packet contents for deep content analysis","B Providing real-time alerts when network traffic exceeds defined thresholds","C Managing network device configurations and monitoring performance","D Analyzing metadata about network connections to detect anomalies and threats without full packet capture"], correct:3, explanation:"Network flow analysis uses connection metadata (NetFlow, IPFIX)—source/destination, ports, bytes, duration—to detect anomalies like port scanning, data exfiltration, and lateral movement without the overhead of full packet capture." },
  { id:30714, domain:7, level:2, question:"What is the significance of privilege abuse in insider threat scenarios?", options:["A Insiders with privileges are always more dangerous than external attackers","B Legitimate privileges provide insiders access to sensitive data and systems without triggering standard intrusion alarms","C Privilege abuse only occurs in organizations with poor access control policies","D Insider threats exclusively use technical exploits rather than legitimate access"], correct:1, explanation:"Insiders with legitimate privileges can access sensitive data without triggering signature-based detection—they're using access they're authorized to have. Behavioral analytics and least-privilege are key controls for detecting and limiting insider abuse." },
  { id:30715, domain:7, level:2, question:"What is the purpose of a security tool integration strategy?", options:["A Reducing software vendor costs through consolidation","B Enabling security tools to share data and coordinate responses for more effective defense","C Meeting compliance requirements for security technology deployment","D Standardizing security technology across departments"], correct:1, explanation:"Security tool integration enables data sharing (EDR → SIEM → SOAR), automated response workflows, and unified visibility, eliminating silos that cause attackers to move undetected between visibility gaps." },
  { id:30716, domain:7, level:2, question:"What is a unified endpoint management (UEM) solution?", options:["A A security solution combining EDR, DLP, and encryption on endpoints","B A tool for managing all enterprise endpoints from a single console for security and configuration","C A platform for deploying software updates to all endpoint types","D A centralized authentication system for endpoint access control"], correct:1, explanation:"UEM manages diverse endpoints (Windows, macOS, Linux, iOS, Android) from a single platform, providing security policy enforcement, configuration management, patch deployment, and device compliance visibility across all device types." },
  { id:30717, domain:7, level:2, question:"What is the primary security concern with cloud workload security?", options:["A Cloud workloads are inherently less secure than on-premises workloads","B Cloud providers are responsible for all workload security controls","C Cloud workloads may lack visibility and controls that existed on-premises","D Cloud workloads cannot be monitored by traditional security tools"], correct:2, explanation:"Organizations moving to cloud must rebuild security visibility—traditional network monitoring may not capture cloud-native traffic, EDR must extend to cloud instances, and new attack surfaces (metadata APIs, IAM roles) require new detection approaches." },
  { id:30718, domain:7, level:2, question:"What is the purpose of automated patch management?", options:["A Deploying all patches immediately without testing to minimize exposure windows","B Systematically identifying, testing, and deploying patches to reduce the window of vulnerability exploitation","C Meeting compliance requirements for patch deployment timelines","D Automating the purchase of vendor support contracts for patches"], correct:1, explanation:"Automated patch management identifies vulnerable systems, schedules and deploys patches based on criticality, tracks deployment status, and reduces the window between vulnerability disclosure and patching that attackers exploit." },
  { id:30719, domain:7, level:2, question:"What is the concept of a 'defense degradation' attack?", options:["A An attack that degrades system performance to cause denial of service","B Exploiting security control failures to bypass authentication","C An attack that gradually degrades encryption to enable decryption","D Deliberately disabling security controls (AV, logging, backups) before executing the main attack"], correct:3, explanation:"Defense degradation attacks disable or impair security controls before the main attack—disabling AV, stopping audit logging, deleting backups, or compromising backup infrastructure—to prevent detection and recovery." },
  { id:30720, domain:7, level:2, question:"What is the purpose of a purple team in security operations maturity?", options:["A Providing a second opinion on red team findings","B Creating a combined team that handles both offensive and defensive security","C Improving blue team detection capabilities by collaborating with red team techniques in real-time","D Evaluating security vendors through controlled testing exercises"], correct:2, explanation:"Purple team operations have red team attackers and blue team defenders collaborate in real-time, with red team showing exactly what they did, then tuning detection rules to catch the same techniques—accelerating blue team improvement." },
  { id:30721, domain:7, level:2, question:"What is the primary security risk of misconfigured cloud storage (e.g., S3 buckets)?", options:["A Public misconfiguration exposes stored data to anyone on the internet","B Cloud storage is more expensive when misconfigured","C Misconfigured storage impacts cloud provider SLA guarantees","D Cloud storage misconfigurations cause data corruption"], correct:0, explanation:"Publicly accessible cloud storage buckets have exposed billions of sensitive records—customer data, credentials, backups, intellectual property—through simple misconfigurations (public read access), requiring cloud security posture management." },
  { id:30722, domain:7, level:2, question:"What is a cloud security posture management (CSPM) tool?", options:["A A tool for encrypting data stored in cloud services","B A tool for managing cloud provider contracts and SLAs","C A tool that continuously monitors cloud infrastructure for misconfigurations and compliance violations","D A tool for monitoring cloud application performance"], correct:2, explanation:"CSPM tools continuously assess cloud infrastructure (AWS, Azure, GCP) configurations against security best practices and compliance frameworks, detecting misconfigurations like public S3 buckets or overly permissive security groups." },
  { id:30723, domain:7, level:2, question:"What is the security implication of API keys stored in source code repositories?", options:["A API keys in repositories are encrypted by default","B API keys in repositories require additional authentication to use","C Source code repositories are secured by access controls preventing exposure","D Public repositories expose API keys to attackers who can use them to access connected services"], correct:3, explanation:"Hardcoded API keys and secrets accidentally committed to repositories (especially public GitHub) are rapidly discovered by automated scanning tools and exploited, often within minutes, to abuse cloud services and data." },
  { id:30724, domain:7, level:2, question:"What is the primary purpose of runtime protection in cloud environments?", options:["A Encrypting all data processed by cloud applications","B Managing the runtime configuration of cloud infrastructure","C Detecting and blocking threats against running workloads including container escape and cryptomining","D Monitoring cloud application performance metrics"], correct:2, explanation:"Runtime protection (cloud workload protection platforms) monitors running containers and VMs for threats like container escapes, cryptocurrency mining, lateral movement, and abnormal process execution—providing detection when prevention fails." },
  { id:30725, domain:7, level:2, question:"What is infrastructure security's relationship to application security?", options:["A Infrastructure provides the foundation; applications run on it, so both layers require independent security controls","B Infrastructure security is more important than application security","C Infrastructure security fully compensates for application security weaknesses","D Application security is more important because infrastructure is the provider's responsibility"], correct:0, explanation:"Infrastructure and application security are complementary layers—strong infrastructure security (hardened OS, network segmentation) limits blast radius of application vulnerabilities, while application security prevents attacks that infrastructure can't see." },
  { id:30726, domain:1, level:2, question:"What is the purpose of an information security risk register?", options:["A A legal register of all security-related incidents and breaches","B A catalog of security tools deployed in the environment","C A register of all employees with access to sensitive information","D A documented inventory of identified risks, their assessments, and treatment decisions"], correct:3, explanation:"A risk register documents identified risks, their likelihood and impact assessments, current controls, risk owners, treatment decisions, and residual risk levels, providing a management view of the organization's risk landscape." },
  { id:30727, domain:1, level:2, question:"What is the concept of 'security by obscurity' and why is it insufficient alone?", options:["A Relying on secrecy of implementation as the primary security mechanism, which fails when secrets are revealed","B Keeping security mechanisms hidden to avoid targeted attacks","C Using obfuscation techniques to make malware analysis difficult","D Concealing sensitive data within ordinary-looking files"], correct:0, explanation:"Security by obscurity uses secrecy of design/implementation as a primary defense. It's insufficient because secrets can be reverse-engineered or leaked—security must hold even when the design is known (Kerckhoffs's principle)." },
  { id:30728, domain:1, level:2, question:"What is the purpose of a vendor risk management program?", options:["A Assessing and managing security risks posed by third-party vendors and suppliers","B Negotiating the best prices with security vendors","C Managing relationships with vendors providing security tools","D Tracking security incidents caused by vendor products"], correct:0, explanation:"Vendor risk management assesses whether third parties with access to organizational data or systems meet security requirements, monitoring ongoing compliance and managing risk through contractual obligations and periodic assessments." },
  { id:30729, domain:1, level:2, question:"What is the concept of quantitative risk assessment?", options:["A Assessing risk using qualitative labels like high, medium, and low","B Assigning ranks to risks based on relative importance","C Assigning numerical values to risk likelihood and impact for financial analysis","D Counting the number of vulnerabilities to quantify risk exposure"], correct:2, explanation:"Quantitative risk assessment assigns monetary values to assets, calculates SLE and ALE, and produces financial risk figures enabling direct cost-benefit analysis of controls versus risk reduction—though uncertainty in estimates can limit precision." },
  { id:30730, domain:1, level:2, question:"What is the concept of qualitative risk assessment?", options:["A Using quality-focused experts to assess security risks","B Rating risks using descriptive scales (high/medium/low) based on expert judgment","C Qualifying risks for inclusion in the formal risk register","D Assessing risk quality based on completeness of risk documentation"], correct:1, explanation:"Qualitative risk assessment uses descriptive scales (high/medium/low, 1-5) and expert judgment to prioritize risks without requiring precise monetary calculations, making it faster and practical when precise data isn't available." },
  { id:30731, domain:1, level:2, question:"What is the purpose of a security awareness phishing simulation?", options:["A Testing email security gateways for phishing detection capability","B Testing the incident response team's capability to investigate phishing events","C Identifying employees who have been trained in phishing techniques","D Measuring and training employees to recognize and report phishing through simulated attacks"], correct:3, explanation:"Phishing simulations send controlled fake phishing emails to employees, measuring click and credential submission rates, then providing immediate training to those who fall for the simulation, building organizational resilience." },
  { id:30732, domain:1, level:2, question:"What is the concept of a security training needs analysis?", options:["A Analyzing security incidents to identify training failures","B Reviewing security training materials for technical accuracy","C Identifying employees who require mandatory security certification","D Assessing what security training is needed based on roles, responsibilities, and identified gaps"], correct:3, explanation:"Training needs analysis determines what security knowledge and skills are needed for specific roles, assesses current capability levels, and identifies gaps requiring training, ensuring training is targeted and effective." },
  { id:30733, domain:1, level:2, question:"What is the concept of 'privacy by default'?", options:["A Privacy settings are publicly available by default","B Privacy is the default compliance requirement for all data processing","C Systems process only necessary data and apply maximum privacy settings unless users actively choose otherwise","D Systems default to requiring privacy impact assessments for all features"], correct:2, explanation:"Privacy by default (GDPR principle) requires that by default systems process only the minimum necessary data and apply the highest privacy settings, without users having to actively request privacy protection." },
  { id:30734, domain:1, level:2, question:"What does 'lawful basis for processing' require under GDPR?", options:["A Organizations must have a valid legal basis (consent, contract, legal obligation, etc.) before processing personal data","B All data processing must be authorized by national data protection authorities","C Data processing must comply with all applicable national laws","D Organizations must obtain legal advice before processing sensitive personal data"], correct:0, explanation:"GDPR requires a lawful basis for every processing activity—consent, contract performance, legal obligation, vital interests, public task, or legitimate interests—before processing personal data. Processing without a lawful basis is prohibited." },
  { id:30735, domain:1, level:2, question:"What is the purpose of a security incident notification requirement?", options:["A Legal or regulatory obligations to notify affected parties when their data is breached","B Requiring security teams to notify management of all alert events","C Policy requirements for security staff to log all incidents","D Contractual requirements to notify clients of security updates"], correct:0, explanation:"Breach notification requirements (GDPR 72 hours, US state laws) mandate timely notification of regulators and/or affected individuals when personal data breaches meet defined thresholds, enabling individuals to protect themselves." },
  { id:30736, domain:2, level:2, question:"What is the concept of data governance?", options:["A Technical controls managing database security and access","B Regulatory compliance for data privacy and protection","C The policies, processes, and standards ensuring data is managed as a valuable organizational asset","D Government regulations governing organizational data practices"], correct:2, explanation:"Data governance establishes policies, processes, roles, and standards for managing data across its lifecycle—ensuring data quality, security, privacy, and appropriate use—treating data as a strategic organizational asset." },
  { id:30737, domain:2, level:2, question:"What is the security implication of data aggregation?", options:["A Combining individually innocuous data items can reveal sensitive information not apparent from any single item","B Aggregating data improves security by centralizing access controls","C Aggregated data requires less encryption than individual records","D Data aggregation reduces the risk of targeted attacks on individual records"], correct:0, explanation:"Data aggregation creates privacy and security risks when combining non-sensitive individual data points reveals sensitive information—e.g., combining browsing habits, location, purchase history can reveal medical conditions or political views." },
  { id:30738, domain:2, level:2, question:"What is the primary purpose of a data flow diagram (DFD) in security?", options:["A Mapping how data moves through systems to identify where it is processed and what security controls apply","B Diagramming network traffic flows for firewall rule design","C Creating documentation for application architecture reviews","D Designing database schemas for secure data storage"], correct:0, explanation:"DFDs map data flows between processes, data stores, and external entities, identifying where data enters/exits systems, crosses trust boundaries, and is transformed, enabling identification of where security controls are needed." },
  { id:30739, domain:2, level:2, question:"What is the purpose of an asset management system in security?", options:["A Managing the procurement of security tools and licenses","B Managing financial assets and technology investments","C Tracking all technology assets to ensure security controls are applied and vulnerabilities are managed","D Tracking employee assets assigned for business use"], correct:2, explanation:"Asset management inventories all hardware, software, and data assets, providing the foundation for vulnerability management (you can't protect what you don't know about), compliance, and incident response (determining blast radius)." },
  { id:30740, domain:2, level:2, question:"What is the concept of data lifecycle security?", options:["A Applying appropriate security controls at each phase of data's lifecycle from creation to disposal","B The security controls applied to data at the end of its life during disposal","C Managing security vulnerabilities over the lifecycle of database systems","D Tracking data through its lifecycle for compliance audit purposes"], correct:0, explanation:"Data lifecycle security applies appropriate controls at each phase—creation (classification), storage (encryption, access control), use (DLP, monitoring), sharing (need-to-know), archival (retention policies), and disposal (secure deletion)." },
  { id:30741, domain:3, level:2, question:"What is a privileged access workstation (PAW)?", options:["A A workstation used exclusively by security administrators","B A dedicated, hardened workstation used only for privileged administrative tasks to prevent credential theft","C A virtual machine providing privileged access to cloud resources","D A laptop with encrypted storage for privileged users while traveling"], correct:1, explanation:"A PAW is a dedicated, hardened device used exclusively for privileged tasks (domain admin, cloud admin), isolated from email and browsing, dramatically reducing the risk of credential theft through malware or phishing on shared-use devices." },
  { id:30742, domain:3, level:2, question:"What is the primary security concern with unpatched vulnerabilities in IoT devices?", options:["A IoT devices consume excessive network bandwidth","B IoT devices store sensitive data without adequate encryption","C IoT devices are incompatible with enterprise security monitoring tools","D IoT devices often lack update mechanisms and contain persistent vulnerabilities that can be exploited at scale"], correct:3, explanation:"IoT devices frequently lack automatic update mechanisms, have long deployment lifespans, and have known vulnerabilities that vendors never patch, creating persistent attack surfaces that can be exploited for botnet recruitment or network access." },
  { id:30743, domain:3, level:2, question:"What is the purpose of a security architecture review board?", options:["A Approving all new security tool purchases","B Reviewing technology and architecture decisions for security implications before implementation","C Conducting security assessments of production systems","D Managing the security architecture documentation process"], correct:1, explanation:"Architecture review boards evaluate proposed systems and changes for security implications—reviewing design patterns, data flows, authentication models, and control placements—before implementation to prevent costly retrofits." },
  { id:30744, domain:3, level:2, question:"What is the concept of defense in depth applied to identity?", options:["A Having multiple identity providers for redundancy","B Layering identity controls: strong authentication, least privilege, monitoring, and just-in-time access","C Requiring users to authenticate to multiple systems independently","D Implementing backup authentication methods if primary factors fail"], correct:1, explanation:"Defense in depth for identity combines multiple controls: strong MFA (preventing credential theft success), least privilege (limiting impact of compromise), behavioral analytics (detecting abuse), and PAM (controlling privileged access)." },
  { id:30745, domain:3, level:2, question:"What is the security concern with serialization in object-oriented systems?", options:["A Serialization makes objects unavailable during conversion","B Serialized data is unencrypted and susceptible to interception","C Serialization formats are often proprietary and difficult to audit","D Deserializing untrusted data can trigger code execution or logic manipulation attacks"], correct:3, explanation:"Insecure deserialization of untrusted input can trigger unintended code execution, modify application logic, conduct DoS attacks, or bypass authentication—because deserialization reconstructs objects, it can execute code during the reconstruction process." },
  { id:30746, domain:3, level:2, question:"What is the primary purpose of patch testing before deployment?", options:["A Verifying that patches don't break existing functionality or introduce new vulnerabilities","B Meeting compliance requirements for change management documentation","C Ensuring patches are from legitimate vendor sources","D Documenting patch deployment for audit purposes"], correct:0, explanation:"Patch testing in a non-production environment verifies that patches function correctly, don't break existing functionality, and don't introduce new problems before deploying to production, reducing operational risk from patching." },
  { id:30747, domain:3, level:2, question:"What is cloud native security and its primary challenge?", options:["A Security solutions built specifically for each cloud provider","B Security that relies exclusively on cloud provider native services","C Security adapted to cloud-native architectures (containers, microservices, serverless) with new attack surfaces","D Security controls that move with workloads across cloud regions"], correct:2, explanation:"Cloud-native security addresses the unique challenges of containerized microservices, serverless functions, and dynamic infrastructure—ephemeral workloads requiring runtime protection, automated security pipelines, and cloud-specific IAM controls." },
  { id:30748, domain:3, level:2, question:"What is the purpose of network microsegmentation in modern architectures?", options:["A Dividing networks into small segments for better performance","B Applying granular east-west traffic controls between individual workloads to limit lateral movement","C Encrypting all traffic between network segments","D Creating separate network zones for different security classification levels"], correct:1, explanation:"Microsegmentation applies security policies at workload/application level, restricting which services can communicate with which, ensuring a compromised workload can only reach explicitly permitted services—dramatically limiting lateral movement." },
  { id:30749, domain:3, level:2, question:"What is the concept of security posture management for cloud?", options:["A Managing the physical posture of cloud data center facilities","B Managing security staff postures and responsibilities in cloud operations","C Continuously assessing and improving cloud infrastructure security configurations","D Reporting cloud security posture to regulatory authorities"], correct:2, explanation:"Cloud Security Posture Management (CSPM) continuously assesses cloud infrastructure configurations against security baselines, detecting drift, misconfigurations, and compliance violations across multi-cloud environments in real-time." },
  { id:30750, domain:3, level:2, question:"What is the primary security design consideration for mobile applications?", options:["A Mobile apps should use the same security standards as desktop applications","B Mobile security is primarily the operating system's responsibility","C Mobile apps need specific controls for device storage, certificate validation, and API authentication given the mobile threat model","D Mobile apps should minimize security controls to improve user experience on small devices"], correct:2, explanation:"Mobile apps require specific security controls: protecting local data storage from extraction, SSL pinning against network interception, secure API token management, biometric authentication integration, and protection against runtime manipulation." },
  { id:30751, domain:4, level:2, question:"What is the purpose of software-defined networking (SDN) in security?", options:["A Replacing hardware security devices with software implementations","B Providing software-based encryption for all network traffic","C Enabling dynamic, centralized control of network security policies and automated response to threats","D Creating software-defined security perimeters around applications"], correct:2, explanation:"SDN separates the control plane from the data plane, enabling centralized, programmable network management—dynamically applying security policies, automatically quarantining compromised hosts, and rapidly responding to detected threats." },
  { id:30752, domain:4, level:2, question:"What is the concept of network visibility in security operations?", options:["A Ensuring security staff can see all physical network infrastructure","B Comprehensive insight into all network traffic, connections, and behaviors across the environment","C Providing network performance visibility to operations teams","D Making network architecture visible to business stakeholders"], correct:1, explanation:"Network visibility encompasses full understanding of all traffic flows, protocols, endpoints, and behaviors across east-west and north-south traffic—essential for threat detection, incident response, and understanding the full impact of incidents." },
  { id:30753, domain:4, level:2, question:"What is the security risk of unencrypted inter-service communication in microservices?", options:["A Unencrypted communication reduces microservice performance","B Internal services don't require encryption because they're behind the perimeter","C Unencrypted communication increases cloud provider costs","D Internal traffic interception or compromised services can access all unencrypted inter-service data"], correct:3, explanation:"In microservices, a compromised internal service can intercept all unencrypted inter-service traffic, extracting sensitive data. Mutual TLS (mTLS) between services encrypts traffic and authenticates services to each other." },
  { id:30754, domain:4, level:2, question:"What does a network intrusion prevention system (NIPS) do that an IDS cannot?", options:["A NIPS actively blocks detected attacks inline; IDS only detects and alerts","B NIPS can detect more attack patterns than IDS","C NIPS monitors all network layers; IDS only monitors Layer 3","D NIPS is deployed at the host; IDS is network-based"], correct:0, explanation:"An IDS passively monitors and alerts on detected threats; an IPS sits inline in the traffic path and can actively block, drop, or modify malicious traffic, providing automated prevention rather than just detection." },
  { id:30755, domain:4, level:2, question:"What is the security purpose of traffic shaping and QoS in security operations?", options:["A Improving performance of security tools by prioritizing their traffic","B Managing costs for cloud network traffic","C Encrypting network traffic for different quality levels","D Limiting bandwidth for specific protocols that can be used for exfiltration or command-and-control"], correct:3, explanation:"Traffic shaping can restrict bandwidth for protocols commonly used for exfiltration (large FTP transfers, unusual DNS volumes) or C2 (periodic beaconing), complementing detection with friction that limits attacker efficiency." },
  { id:30756, domain:4, level:2, question:"What is the purpose of SSL/TLS inspection in enterprise security?", options:["A Inspecting encrypted traffic for threats by decrypting, inspecting, and re-encrypting it","B Accelerating TLS performance by offloading decryption to dedicated hardware","C Validating TLS certificate chains for all web connections","D Ensuring all traffic uses current TLS versions and strong cipher suites"], correct:0, explanation:"SSL/TLS inspection decrypts traffic at a proxy, inspects content for threats (malware, exfiltration, policy violations), then re-encrypts it, providing visibility into the 80%+ of traffic now encrypted that would otherwise be opaque to security tools." },
  { id:30757, domain:4, level:2, question:"What is the concept of a network access control (NAC) quarantine network?", options:["A A network segment for storing sensitive data under strict controls","B An isolated network segment to which non-compliant or suspected devices are redirected for remediation","C A network segment exclusively for security monitoring equipment","D A backup network segment activated during incident response"], correct:1, explanation:"NAC quarantine networks isolate devices that fail compliance checks (missing patches, no AV), restricting them to remediation resources (patch servers, AV updates) until they meet requirements, preventing non-compliant devices from accessing production networks." },
  { id:30758, domain:4, level:2, question:"What is the security risk of BGP hijacking?", options:["A BGP protocol weaknesses allow unauthorized routers to join BGP sessions","B BGP hijacking allows attackers to modify DNS records for large domains","C BGP configuration errors cause routing loops that disable internet connectivity","D Attackers can reroute internet traffic through malicious AS to intercept or disrupt communications"], correct:3, explanation:"BGP hijacking involves announcing more-specific routes to steal traffic intended for legitimate networks, enabling interception (MITM), censorship, or denial of service for large portions of internet infrastructure." },
  { id:30759, domain:4, level:2, question:"What is RPKI (Resource Public Key Infrastructure) used for?", options:["A Cryptographically validating BGP route announcements to prevent prefix hijacking","B Providing PKI services for web server certificates","C Managing IP address assignments across internet registries","D Securing DNS resource records with cryptographic signatures"], correct:0, explanation:"RPKI allows networks to cryptographically sign their IP address blocks, creating Route Origin Authorizations (ROAs) that BGP routers can verify, preventing unauthorized prefix announcements and BGP hijacking attacks." },
  { id:30760, domain:4, level:2, question:"What is the purpose of network segmentation for operational technology (OT) security?", options:["A Improving OT network performance by reducing broadcast traffic","B Isolating industrial control systems from IT networks to prevent IT threats from reaching critical infrastructure","C Enabling remote access to OT systems for maintenance purposes","D Providing separate network bandwidth for OT and IT systems"], correct:1, explanation:"OT/IT network segmentation prevents IT network threats (ransomware, APTs) from directly reaching industrial control systems and SCADA infrastructure, protecting critical infrastructure from cyber threats that could cause physical damage or safety incidents." },
  { id:30761, domain:5, level:2, question:"What is the primary security consideration for API gateway authentication?", options:["A API gateways should authenticate once and cache results for performance","B API gateways should validate authentication tokens and enforce authorization for every request","C API authentication is the responsibility of individual microservices","D API gateways should use network-layer security instead of application-layer authentication"], correct:1, explanation:"API gateways must validate authentication tokens (JWT, OAuth) and enforce authorization on every request, providing a centralized enforcement point that ensures no API call bypasses security controls regardless of the calling service." },
  { id:30762, domain:5, level:2, question:"What is the concept of identity as a security perimeter?", options:["A Replacing network perimeters with user identity as the primary access control boundary","B Using identity documents as the first line of physical security","C Identifying the perimeter of the organization's digital attack surface","D Treating all users as potential threats regardless of their identity"], correct:0, explanation:"As network perimeters dissolve with cloud adoption, identity becomes the primary security control boundary—every access request verified against identity, device state, and context, rather than relying on network location to grant trust." },
  { id:30763, domain:5, level:2, question:"What is adaptive authentication and when is it triggered?", options:["A Authentication that adapts to different device types and form factors","B Authentication that changes strength based on network connection quality","C Authentication that adapts to regulatory requirements in different jurisdictions","D Authentication that adjusts required factors based on evaluated risk signals"], correct:3, explanation:"Adaptive authentication evaluates risk signals (unusual location, new device, suspicious behavior, time) and dynamically adjusts authentication requirements—adding MFA challenges when risk is elevated, streamlining when risk is low." },
  { id:30764, domain:5, level:2, question:"What is the primary security benefit of hardware-backed authentication?", options:["A Hardware authentication is faster than software-based alternatives","B Hardware tokens provide offline authentication without network connectivity","C Private keys stored in hardware cannot be extracted even if the device is compromised","D Hardware authentication is cheaper to deploy than software tokens"], correct:2, explanation:"Hardware-backed authentication (TPM, secure enclave, hardware security key) stores private keys in tamper-resistant hardware, making key extraction impossible even if malware fully compromises the device OS—preventing phishing and malware from stealing credentials." },
  { id:30765, domain:5, level:2, question:"What is the concept of identity lifecycle management?", options:["A Managing the lifespan of digital identity documents and certificates","B Tracking identity changes for compliance and audit purposes","C Governing the complete lifecycle of identities from creation through role changes to deprovisioning","D Managing identity provider infrastructure from deployment to retirement"], correct:2, explanation:"Identity lifecycle management governs all identity events—joiners (provisioning), movers (role changes requiring access updates), and leavers (deprovisioning)—ensuring identities remain accurate, appropriate, and deprovisioned when no longer needed." },
  { id:30766, domain:5, level:2, question:"What is the security risk of long-lived API tokens and how should they be managed?", options:["A Long-lived tokens perform better than short-lived tokens","B Long-lived tokens that are stolen provide extended access; tokens should be short-lived with rotation","C Long-lived tokens are acceptable if stored encrypted in secure vaults","D Long-lived tokens only need rotation when potential compromise is detected"], correct:1, explanation:"Long-lived tokens provide attackers extended access if stolen. Best practices use short-lived access tokens (minutes/hours), refresh tokens with rotation, and secrets management tools that auto-rotate credentials." },
  { id:30767, domain:5, level:2, question:"What is the purpose of a privileged access management (PAM) vault?", options:["A Securely storing, rotating, and auditing privileged credentials with session recording","B Physical storage for hardware security tokens and smart cards","C Encrypting privileged account passwords using a master key","D Storing backup copies of privileged credentials for disaster recovery"], correct:0, explanation:"PAM vaults securely store privileged credentials, automatically rotate passwords on checkout/check-in, record privileged sessions, and provide approval workflows—ensuring credentials are never directly known to users and all access is audited." },
  { id:30768, domain:5, level:2, question:"What is the primary challenge in managing non-human identities in modern environments?", options:["A Non-human identities require special certificates that are difficult to obtain","B Service accounts, API keys, and tokens proliferate rapidly and often lack the lifecycle controls applied to human identities","C Non-human identities cannot be enrolled in multi-factor authentication","D Non-human identities are not subject to regulatory compliance requirements"], correct:1, explanation:"Non-human identities (service accounts, API keys, containers, CI/CD pipelines) proliferate rapidly in cloud environments and often lack lifecycle management—long-lived, over-privileged, and not rotated—creating significant credential risk." },
  { id:30769, domain:5, level:2, question:"What is the difference between authorization and access control?", options:["A Authorization is a policy decision; access control is the same decision made technically","B Authorization is automatic; access control requires manual approval","C Authorization applies to users; access control applies to systems","D Authorization determines what you can do; access control enforces it"], correct:3, explanation:"Authorization is the policy decision—determining what an authenticated identity is permitted to do. Access control is the enforcement mechanism that implements the authorization decision, either granting or denying the request." },
  { id:30770, domain:5, level:2, question:"What is the security purpose of session invalidation on logout?", options:["A Freeing server resources associated with the user's session","B Preventing session token reuse to impersonate logged-out users","C Complying with privacy regulations requiring data deletion on request","D Improving application performance by reducing active session count"], correct:1, explanation:"Server-side session invalidation on logout ensures that even if a session token is captured (via XSS, network sniffing, or shoulder surfing), it cannot be reused after the legitimate user has logged out." },
  { id:30771, domain:6, level:2, question:"What is the purpose of a vulnerability disclosure policy?", options:["A Documenting how the organization discloses security vulnerabilities to regulators","B Establishing timeframes for disclosing breaches to affected individuals","C Defining how external researchers can responsibly report discovered vulnerabilities","D Setting standards for how vulnerabilities are prioritized in the remediation process"], correct:2, explanation:"A vulnerability disclosure policy (coordinated vulnerability disclosure) establishes a safe harbor and process for security researchers to report discovered vulnerabilities, enabling remediation before public disclosure rather than immediate full disclosure." },
  { id:30772, domain:6, level:2, question:"What is the difference between a vulnerability scan and a network discovery scan?", options:["A Vulnerability scans cover more systems than discovery scans","B Discovery scans identify live hosts and services; vulnerability scans test for specific known weaknesses","C Discovery scans require credentials; vulnerability scans are unauthenticated","D Vulnerability scans only cover application layer; discovery covers all layers"], correct:1, explanation:"Discovery scans map the network (live hosts, open ports, services, OS versions). Vulnerability scans build on discovery to test for specific known vulnerabilities using CVE databases, checking whether identified services have known exploitable weaknesses." },
  { id:30773, domain:6, level:2, question:"What is the primary limitation of automated security scanning?", options:["A Automated scanners are too expensive for small organizations","B Scanners can only identify known vulnerabilities and may miss logic flaws or novel attack combinations","C Automated scanners generate excessive false positives making results unusable","D Automated scanners require extensive manual configuration for accurate results"], correct:1, explanation:"Automated scanners find known CVEs and common misconfigurations but cannot understand application-specific logic flaws, business context, chained attack scenarios, or vulnerabilities requiring human reasoning—manual testing is needed to complement automation." },
  { id:30774, domain:6, level:2, question:"What is the purpose of a security assessment scope statement?", options:["A Defining what is included and excluded from the security assessment to prevent scope creep and set expectations","B Documenting the tools approved for use during the assessment","C Describing the methodology the assessment team will follow","D Establishing the budget and timeline for the security assessment"], correct:0, explanation:"Scope statements clearly define what systems, applications, and processes are in scope, what is explicitly excluded, geographic/logical boundaries, and testing constraints—preventing disputes and ensuring the assessment delivers targeted results." },
  { id:30775, domain:6, level:2, question:"What is the concept of attack simulation in security testing?", options:["A Creating simulated environments for practicing attack techniques","B Simulating attacks on paper to identify theoretical vulnerabilities","C Executing actual adversary techniques (MITRE ATT&CK TTPs) against production or lab environments to test defenses","D Training security analysts using gamified attack scenarios"], correct:2, explanation:"Attack simulation (breach and attack simulation—BAS) continuously or periodically executes automated adversary TTPs to validate that security controls detect and prevent specific techniques, providing ongoing security control validation." },
  { id:30776, domain:6, level:2, question:"What is an application security scanning false positive?", options:["A A scan result showing a critical vulnerability when none exists","B A scan that misses real vulnerabilities due to incomplete code coverage","C A scan result incorrectly identifying code as vulnerable when it is not actually exploitable","D A scan result that understates the severity of a real vulnerability"], correct:2, explanation:"False positives are scan results flagging non-existent vulnerabilities, wasting developer time investigating benign code. False negatives (missed real vulnerabilities) are also critical—scanners must be tuned to balance both error types." },
  { id:30777, domain:6, level:2, question:"What is the purpose of a penetration test final report?", options:["A Documenting discovered vulnerabilities with evidence, risk rating, and actionable remediation guidance","B Fulfilling the contractual deliverable for the engagement","C Providing a legal record of authorized testing activities","D Comparing security maturity against industry benchmarks"], correct:0, explanation:"Pentest reports document: executive summary (business risk), technical findings (with evidence/proof-of-concept), risk ratings, and specific remediation recommendations—enabling organizations to prioritize and fix discovered vulnerabilities." },
  { id:30778, domain:6, level:2, question:"What is the concept of a security maturity model?", options:["A A framework measuring and guiding the progression of security program capabilities over time","B A model describing how security threats mature over time","C A model assessing the maturity of security professionals in an organization","D A framework measuring how mature (old) security technology is in the environment"], correct:0, explanation:"Security maturity models (CMMI, NIST CSF tiers, BSIMM) provide levels of capability maturity—from ad-hoc to optimized—helping organizations understand their current state, set targets, and prioritize improvements." },
  { id:30779, domain:6, level:2, question:"What does a security operations center (SOC) maturity assessment evaluate?", options:["A The technical capabilities of the security tools deployed in the SOC","B The compliance posture of the organization's security program","C The physical security of the SOC facility and infrastructure","D The processes, people, technology, and metrics capabilities of the security operations function"], correct:3, explanation:"SOC maturity assessments evaluate capability across multiple dimensions—detection effectiveness, response speed, analyst skills, process maturity, technology integration, metrics quality—providing a comprehensive view of operational security effectiveness." },
  { id:30780, domain:6, level:2, question:"What is the purpose of security testing for cloud infrastructure?", options:["A Testing the physical security of cloud provider data centers","B Evaluating cloud provider security certifications and compliance reports","C Testing cloud provider SLA commitments through availability testing","D Validating cloud configurations, IAM policies, and security controls meet requirements"], correct:3, explanation:"Cloud security testing validates that infrastructure-as-code, IAM configurations, network controls, storage permissions, and security service configurations actually meet security requirements, catching misconfigurations before they expose data." },
  { id:30781, domain:7, level:2, question:"What is the primary purpose of a security runbook?", options:["A Documenting security architecture decisions and rationale","B Tracking security team tasks and assignments","C Recording security incidents for regulatory reporting","D Providing repeatable, step-by-step procedures for executing common security tasks and responses"], correct:3, explanation:"Security runbooks provide detailed, repeatable procedures for specific operational tasks (alert investigation, account lockout response, vulnerability scanning), ensuring consistent execution quality regardless of which analyst handles the task." },
  { id:30782, domain:7, level:2, question:"What is the concept of security operations automation?", options:["A Replacing all manual security tasks with fully automated systems","B Automating the procurement and deployment of security tools","C Using scripts, APIs, and platforms to automate repetitive security tasks, accelerating response and reducing human error","D Automatically enforcing security policies on all systems"], correct:2, explanation:"Security automation uses scripts, SOAR platforms, and API integrations to automate repetitive tasks (phishing triage, IOC extraction, account isolation, ticket creation), freeing analysts for complex investigation and decision-making." },
  { id:30783, domain:7, level:2, question:"What is the purpose of a deception-in-depth strategy?", options:["A Training security staff to deceive attackers during negotiations","B Using marketing messaging to deceive potential attackers about the organization's defenses","C Deceiving auditors about the state of security controls","D Deploying layers of deception (honeytokens, honeypots, breadcrumbs) throughout the environment to detect attackers at every stage"], correct:3, explanation:"Deception-in-depth plants multiple types of decoys throughout the kill chain—honeytokens in code repos, fake credentials in user stores, honeypot servers—creating high-confidence alerts when attackers touch any decoy during their intrusion." },
  { id:30784, domain:7, level:2, question:"What is a security event correlation engine?", options:["A Hardware that accelerates security data processing","B Software that analyzes relationships between events from multiple sources to identify attack patterns","C A tool that correlates security findings with business risk priorities","D A platform for correlating threat intelligence from multiple vendors"], correct:1, explanation:"Correlation engines analyze events from multiple sources simultaneously, applying rules and ML to identify patterns spanning systems that individually appear benign—connecting the dots to surface attack campaigns that single-source analysis would miss." },
  { id:30785, domain:7, level:2, question:"What is the primary security concern with cloud instance metadata services?", options:["A Instance metadata services can expose IAM credentials to attackers who achieve SSRF or instance access","B Metadata services expose cloud provider pricing and billing information","C Metadata services slow down cloud instance performance","D Metadata services are accessible only to cloud administrators"], correct:0, explanation:"Cloud instance metadata endpoints (169.254.169.254) provide IAM role credentials to instances. SSRF vulnerabilities or compromised instances can fetch these credentials, granting the attacker the instance's cloud permissions—like in the Capital One breach." },
  { id:30786, domain:7, level:2, question:"What is the purpose of network deception in threat detection?", options:["A Deploying decoy assets that generate high-confidence alerts when accessed by attackers","B Misdirecting DDoS attack traffic to less critical systems","C Deceiving network monitoring tools to test detection accuracy","D Creating redundant network paths to confuse network mapping tools"], correct:0, explanation:"Network deception (honeypots, dark IP space monitoring, fake open ports) creates assets with no legitimate access, generating virtually zero false positives—any interaction is suspicious, providing early warning of reconnaissance and lateral movement." },
  { id:30787, domain:7, level:2, question:"What is the primary challenge of securing remote work environments?", options:["A Remote workers are less productive than office-based workers","B Endpoints outside the corporate perimeter are harder to control, monitor, and protect","C Remote access creates excessive VPN bandwidth costs","D Remote workers have less access to security training resources"], correct:1, explanation:"Remote work extends the security perimeter to home networks and personal devices—outside IT control, harder to monitor, and more exposed to household threats—requiring zero trust architecture, strong endpoint security, and secure remote access solutions." },
  { id:30788, domain:7, level:2, question:"What is the security purpose of geolocation controls in access management?", options:["A Optimizing access to regional resources for performance","B Providing personalized user experiences based on location","C Meeting data residency requirements for international operations","D Detecting and blocking access from unexpected geographic locations as a risk signal"], correct:3, explanation:"Geolocation controls flag access attempts from unexpected countries or simultaneous access from geographically impossible locations (impossible travel), providing risk signals for adaptive authentication and potential account compromise detection." },
  { id:30789, domain:7, level:2, question:"What is the concept of threat-informed defense?", options:["A Using threat intelligence to inform security investments and prioritize defenses against likely attackers","B Training security teams with threat-specific exercises","C Informing business leadership about the threat landscape","D Defending against all known threat actors equally"], correct:0, explanation:"Threat-informed defense prioritizes security investments based on the actual threat landscape facing the organization—using threat intelligence about likely adversaries and their TTPs to focus defenses where they'll have the most impact." },
  { id:30790, domain:7, level:2, question:"What is the purpose of cross-domain solutions (CDS) in high-security environments?", options:["A Providing single sign-on across different security domains","B Managing network routing between different organizational domains","C Enabling communication between domains with different trust levels under strict control","D Connecting air-gapped networks to standard internet connectivity"], correct:2, explanation:"Cross-domain solutions provide controlled, monitored, and filtered data transfer between networks of different classification levels (e.g., secret to unclassified), enforcing data flow policies through specialized hardware/software that prevents unauthorized data movement." },
  { id:30791, domain:8, level:2, question:"What is the primary security concern with microservices architectures?", options:["A Microservices are difficult to monitor with traditional security tools","B Microservices require more complex security certificates than monolithic applications","C The increased number of inter-service communications creates a larger attack surface and lateral movement risk","D Microservices cannot implement the same security controls as monolithic applications"], correct:2, explanation:"Microservices multiply communication paths between services, creating many potential lateral movement vectors. Each service becomes a potential entry point, and compromising one service can enable attacks on all services it's authorized to call." },
  { id:30792, domain:8, level:2, question:"What is the concept of serverless security?", options:["A Security applied to FaaS (Function as a Service) platforms with unique considerations for function isolation and permissions","B Security for applications running without dedicated server infrastructure","C Security for applications that don't require authentication","D Security for cloud applications that don't use server-side code"], correct:0, explanation:"Serverless security addresses unique FaaS risks: over-privileged function permissions, event injection (attackers controlling trigger events), function isolation weaknesses, and dependency vulnerabilities in function packages." },
  { id:30793, domain:8, level:2, question:"What is the purpose of software signing (signing packages and containers)?", options:["A Encrypting software packages to prevent unauthorized copying","B Verifying authenticity and integrity of software packages and container images to prevent supply chain attacks","C Digitally identifying software developers for accountability purposes","D Signing off on security reviews before software deployment"], correct:1, explanation:"Code/package signing uses developer or organization private keys to sign artifacts, allowing users to verify that software came from a trusted source and hasn't been tampered with since signing—preventing supply chain attacks via compromised repositories." },
  { id:30794, domain:8, level:2, question:"What is the security risk of inadequate logging in web applications?", options:["A Applications without logging consume less storage resources","B Lack of logging reduces compliance audit requirements","C Applications without logging are faster and more responsive","D Insufficient logging prevents detection, investigation, and forensic reconstruction of attacks"], correct:3, explanation:"Without adequate logging (authentication events, access to sensitive data, errors, admin actions), organizations cannot detect ongoing attacks, investigate incidents, prove compliance, or reconstruct attack timelines for forensic analysis." },
  { id:30795, domain:8, level:2, question:"What is the concept of secure API versioning?", options:["A Maintaining multiple API versions to support different security standards","B Managing API version deprecation to prevent use of older, less secure API versions","C Using version numbers to track security patches in APIs","D Maintaining version history of API specifications for security review"], correct:1, explanation:"Secure API versioning includes a strategy for deprecating old API versions with known vulnerabilities, ensuring clients migrate to current, secure versions rather than continuing to use legacy endpoints with known security weaknesses." },
  { id:30796, domain:8, level:2, question:"What is the primary purpose of a software security incident response plan?", options:["A Defining how to handle discovered vulnerabilities in deployed software—triage, patch, communicate, and verify","B Planning how to respond to incidents caused by software bugs in production","C Managing incidents involving third-party software vendors","D Responding to security incidents targeting the software development environment"], correct:0, explanation:"A software security incident response plan defines how to handle discovered vulnerabilities: severity triage, fix development and testing, deployment procedures, customer/user communication, and verification that the fix resolves the issue." },
  { id:30797, domain:8, level:2, question:"What is the purpose of security in software testing environments?", options:["A Meeting compliance requirements for test environment security","B Providing secure storage for test data and test results","C Ensuring test environments use the same security tools as production","D Preventing test environments from being used as stepping stones to production or as sources of real data exposure"], correct:3, explanation:"Test environments often have weaker security controls, may contain copies of production data, and have network access that could reach production—making them targets for attackers seeking to access sensitive data or pivot to production systems." },
  { id:30798, domain:8, level:2, question:"What is the concept of broken access control in web applications?", options:["A Network access controls that malfunction under load","B Access controls that break under high user loads","C Vulnerabilities where access control checks are missing or incorrectly implemented, allowing unauthorized access","D Physical access control systems with electronic failures"], correct:2, explanation:"Broken access control (#1 OWASP Top 10) encompasses missing authorization checks, IDOR vulnerabilities, privilege escalation, CORS misconfiguration, and directory traversal—allowing users to access resources or perform actions they shouldn't be permitted to do." },
  { id:30799, domain:8, level:2, question:"What is the purpose of content security policy (CSP) in web applications?", options:["A Encrypting sensitive content served to web clients","B Controlling which users can access specific content on a website","C Filtering malicious content submitted by users in forms","D Defining approved sources for content loaded by the browser to mitigate XSS attacks"], correct:3, explanation:"CSP is an HTTP security header that tells browsers which sources are trusted for scripts, styles, and other resources, preventing XSS by blocking execution of scripts not from approved origins—even if injected into the page." },
  { id:30800, domain:8, level:2, question:"What is the security purpose of HTTP Strict Transport Security (HSTS)?", options:["A Encrypting HTTP headers to prevent information leakage","B Enforcing strict content security policies for HTTP responses","C Instructing browsers to only connect via HTTPS, preventing SSL stripping attacks","D Requiring strict certificate validation for all HTTP connections"], correct:2, explanation:"HSTS instructs browsers to only connect to the server via HTTPS, even if a user types http://, preventing SSL stripping attacks where attackers downgrade HTTPS connections to unencrypted HTTP to intercept traffic." }
];
